import psycopg2

def search_users(**kwargs):
    """
    Searches for users in the database based on the given filter criteria.

    Args:
        **kwargs: Filter criteria, e.g., username='john', role='admin', status='active'

    Returns:
        A list of user profiles matching the filter criteria.
    """

    conn = psycopg2.connect("dbname='your_database_name'")
    cursor = conn.cursor()

    query = "SELECT * FROM users WHERE 1=1"
    params = []

    for key, value in kwargs.items():
        query += f" AND {key} = %s"
        params.append(value)

    cursor.execute(query, params)
    users = cursor.fetchall()

    conn.close()

    return users